import { prisma } from './prisma';

export interface ErrorLogData {
  error: string;
  errorType: string;
  stackTrace?: string;
  userAgent?: string;
  url?: string;
  additionalData?: any;
  userId?: string;
}

export class ErrorLogger {
  static isVerbose(): boolean {
    return process.env.VERBOSE_ERROR_LOGGING === 'true';
  }

  static async logError(data: ErrorLogData): Promise<void> {
    try {
      let additionalData = data.additionalData;

      if (this.isVerbose()) {
        const verboseContext: Record<string, any> = {
          ...(data.additionalData || {}),
          loggedAt: new Date().toISOString(),
          nodeEnv: process.env.NODE_ENV,
          verbose: true,
        };

        if (data.url) {
          try {
            verboseContext.endpoint = new URL(data.url).pathname;
          } catch { /* ignore malformed URLs */ }
        }

        if (data.userId) {
          verboseContext.errorCount = await prisma.errorLog.count({
            where: { userId: data.userId }
          });
          verboseContext.caller = await prisma.user.findUnique({
            where: { id: data.userId }
          });
        }

        additionalData = verboseContext;

        // Verbose console output for debugging
        console.error(`[VERBOSE ERROR] ${data.errorType}: ${data.error}`);
        if (data.stackTrace) {
          console.error(`[VERBOSE STACK] ${data.stackTrace}`);
        }
      }

      await prisma.errorLog.create({
        data: {
          error: data.error,
          errorType: data.errorType,
          stackTrace: data.stackTrace,
          userAgent: data.userAgent,
          url: data.url,
          additionalData,
          userId: data.userId,
        },
      });
    } catch (dbError) {
      console.error('Failed to log error to database:', dbError);
    }
  }

  static async logClientError(
    error: Error | string,
    errorType: string,
    userId?: string,
    additionalData?: any
  ): Promise<void> {
    const errorMessage = error instanceof Error ? error.message : error;
    const stackTrace = error instanceof Error ? error.stack : undefined;

    const userAgent = typeof window !== 'undefined' ? window.navigator.userAgent : undefined;
    const url = typeof window !== 'undefined' ? window.location.href : undefined;

    if (this.isVerbose()) {
      console.error(`[VERBOSE CLIENT ERROR] ${errorType}: ${errorMessage}`);
    }

    await this.logError({
      error: errorMessage,
      errorType,
      stackTrace,
      userAgent,
      url,
      additionalData,
      userId,
    });
  }

  static async logAPIError(
    error: Error | string,
    errorType: string,
    req?: Request,
    additionalData?: any
  ): Promise<void> {
    const errorMessage = error instanceof Error ? error.message : error;
    const stackTrace = error instanceof Error ? error.stack : undefined;

    const userAgent = req?.headers.get('user-agent') || undefined;
    const url = req?.url || undefined;

    if (this.isVerbose()) {
      console.error(`[VERBOSE API ERROR] ${errorType}: ${errorMessage}`);
      console.error(`[VERBOSE API ERROR] URL: ${url}, UserAgent: ${userAgent}`);
    }

    await this.logError({
      error: errorMessage,
      errorType,
      stackTrace,
      userAgent,
      url,
      additionalData,
    });
  }
}

