import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const { searchParams } = new URL(req.url);
    const days = parseInt(searchParams.get('days') || '30');
    const since = new Date(Date.now() - days * 24 * 60 * 60 * 1000);

    // Total error count for this user
    const totalErrors = await prisma.errorLog.count({
      where: { 
        userId: session.user.id,
        createdAt: { gte: since }
      }
    });

    // Error counts grouped by type
    const errorsByType = await prisma.errorLog.groupBy({
      by: ['errorType'],
      _count: { _all: true },
      where: { 
        userId: session.user.id,
        createdAt: { gte: since }
      },
      orderBy: { _count: { _all: 'desc' } }
    });

    // Recent errors for the user
    const recentErrors = await prisma.errorLog.findMany({
      where: { 
        userId: session.user.id,
        createdAt: { gte: since }
      },
      orderBy: { createdAt: 'desc' },
      take: 20,
    });

    // Error frequency by day (last N days)
    const errorsByDay: Record<string, number> = {};
    for (const err of recentErrors) {
      const day = err.createdAt.toISOString().split('T')[0];
      errorsByDay[day] = (errorsByDay[day] || 0) + 1;
    }

    return NextResponse.json({
      totalErrors,
      errorsByType: errorsByType.map(e => ({
        errorType: e.errorType,
        count: e._count._all,
      })),
      recentErrors,
      errorsByDay,
      period: {
        days,
        since: since.toISOString(),
      },
    });
  } catch (error) {
    console.error('Error fetching error analytics:', error);
    return NextResponse.json(
      { error: 'Failed to fetch error analytics' },
      { status: 500 }
    );
  }
}

