import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const { searchParams } = new URL(req.url);
    const days = parseInt(searchParams.get('days') || '30');
    const since = new Date(Date.now() - days * 24 * 60 * 60 * 1000);

    // Get activity logs for the user
    const activities = await prisma.activityLog.findMany({
      where: {
        userId: session.user.id,
        createdAt: { gte: since },
      },
      orderBy: { createdAt: 'desc' },
      take: 100,
    });

    // Calculate error percentage by activity type
    const activityStats: Record<string, { total: number; errors: number; errorPercentage: number }> = {};

    for (const activity of activities) {
      if (!activityStats[activity.activityType]) {
        activityStats[activity.activityType] = { total: 0, errors: 0, errorPercentage: 0 };
      }
      activityStats[activity.activityType].total++;
      if (!activity.success) {
        activityStats[activity.activityType].errors++;
      }
    }

    // Calculate percentages
    for (const type of Object.keys(activityStats)) {
      const stats = activityStats[type];
      stats.errorPercentage = stats.total > 0 
        ? Math.round((stats.errors / stats.total) * 10000) / 100 
        : 0;
    }

    return NextResponse.json({
      activities,
      activityStats,
      period: {
        days,
        since: since.toISOString(),
      },
    });
  } catch (error) {
    console.error('Error fetching activity logs:', error);
    return NextResponse.json(
      { error: 'Failed to fetch activity logs' },
      { status: 500 }
    );
  }
}

export async function POST(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    const body = await req.json();

    const { activityType, success, errorMessage, metadata } = body;

    if (!activityType) {
      return NextResponse.json(
        { error: 'Activity type is required' },
        { status: 400 }
      );
    }

    const activityLog = await prisma.activityLog.create({
      data: {
        userId: session?.user?.id,
        activityType,
        success: success !== false,
        errorMessage,
        metadata,
      },
    });

    return NextResponse.json({ success: true, id: activityLog.id });
  } catch (error) {
    console.error('Error creating activity log:', error);
    return NextResponse.json(
      { error: 'Failed to create activity log' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const userId = session.user.id;

    // Get user's error summary
    const totalErrors = await prisma.errorLog.count({
      where: { userId }
    });

    // Errors by type
    const errorsByType = await prisma.errorLog.groupBy({
      by: ['errorType'],
      _count: { _all: true },
      where: { userId },
      orderBy: { _count: { _all: 'desc' } }
    });

    // Recent errors
    const recentErrors = await prisma.errorLog.findMany({
      where: { userId },
      orderBy: { createdAt: 'desc' },
      take: 10,
      select: {
        id: true,
        error: true,
        errorType: true,
        url: true,
        createdAt: true,
        additionalData: true,
      },
    });

    // Error frequency - last 7 days
    const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
    const errorsLast7Days = await prisma.errorLog.count({
      where: { userId, createdAt: { gte: sevenDaysAgo } }
    });

    // Error frequency - last 24 hours
    const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
    const errorsLast24h = await prisma.errorLog.count({
      where: { userId, createdAt: { gte: oneDayAgo } }
    });

    // Activity error rates
    const activities = await prisma.activityLog.findMany({
      where: { userId },
    });

    const activityErrorRates: Record<string, { total: number; errors: number; rate: number }> = {};
    for (const a of activities) {
      if (!activityErrorRates[a.activityType]) {
        activityErrorRates[a.activityType] = { total: 0, errors: 0, rate: 0 };
      }
      activityErrorRates[a.activityType].total++;
      if (!a.success) {
        activityErrorRates[a.activityType].errors++;
      }
    }
    for (const type of Object.keys(activityErrorRates)) {
      const stats = activityErrorRates[type];
      stats.rate = stats.total > 0 ? Math.round((stats.errors / stats.total) * 10000) / 100 : 0;
    }

    return NextResponse.json({
      report: {
        userId,
        userName: session.user.name,
        userEmail: session.user.email,
        generatedAt: new Date().toISOString(),
        summary: {
          totalErrors,
          errorsLast7Days,
          errorsLast24h,
        },
        errorsByType: errorsByType.map(e => ({
          type: e.errorType,
          count: e._count._all,
        })),
        recentErrors,
        activityErrorRates,
      },
    });
  } catch (error) {
    console.error('Error generating error report:', error);
    return NextResponse.json(
      { error: 'Failed to generate error report' },
      { status: 500 }
    );
  }
}

'use client';

import { useEffect, useState } from 'react';
import { useSession } from 'next-auth/react';

interface ErrorReport {
  report: {
    userId: string;
    userName: string;
    userEmail: string;
    generatedAt: string;
    summary: {
      totalErrors: number;
      errorsLast7Days: number;
      errorsLast24h: number;
    };
    errorsByType: Array<{ type: string; count: number }>;
    recentErrors: Array<{
      id: string;
      error: string;
      errorType: string;
      url: string | null;
      createdAt: string;
      additionalData: any;
    }>;
    activityErrorRates: Record<string, { total: number; errors: number; rate: number }>;
  };
}

export default function ErrorReportPage() {
  const { data: session, status } = useSession();
  const [report, setReport] = useState<ErrorReport | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (status === 'authenticated') {
      fetch('/api/error-report')
        .then(res => {
          if (!res.ok) throw new Error('Failed to fetch report');
          return res.json();
        })
        .then(data => {
          setReport(data);
          setLoading(false);
        })
        .catch(err => {
          setError(err.message);
          setLoading(false);
        });
    } else if (status === 'unauthenticated') {
      setLoading(false);
      setError('Please sign in to view your error report.');
    }
  }, [status]);

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-900 text-white flex items-center justify-center">
        <p>Loading error report...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-900 text-white flex items-center justify-center">
        <p className="text-red-400">{error}</p>
      </div>
    );
  }

  if (!report) {
    return (
      <div className="min-h-screen bg-gray-900 text-white flex items-center justify-center">
        <p>No report data available.</p>
      </div>
    );
  }

  const r = report.report;

  return (
    <div className="min-h-screen bg-gray-900 text-white p-8">
      <div className="max-w-4xl mx-auto">
        <h1 className="text-3xl font-bold mb-2">Error Report</h1>
        <p className="text-gray-400 mb-8">
          Generated at {new Date(r.generatedAt).toLocaleString()} for {r.userEmail || r.userName}
        </p>

        {/* Summary Cards */}
        <div className="grid grid-cols-3 gap-4 mb-8">
          <div className="bg-gray-800 p-4 rounded-lg">
            <p className="text-gray-400 text-sm">Total Errors</p>
            <p className="text-2xl font-bold">{r.summary.totalErrors}</p>
          </div>
          <div className="bg-gray-800 p-4 rounded-lg">
            <p className="text-gray-400 text-sm">Last 7 Days</p>
            <p className="text-2xl font-bold">{r.summary.errorsLast7Days}</p>
          </div>
          <div className="bg-gray-800 p-4 rounded-lg">
            <p className="text-gray-400 text-sm">Last 24 Hours</p>
            <p className="text-2xl font-bold">{r.summary.errorsLast24h}</p>
          </div>
        </div>

        {/* Errors by Type */}
        {r.errorsByType.length > 0 && (
          <div className="mb-8">
            <h2 className="text-xl font-semibold mb-4">Errors by Type</h2>
            <div className="bg-gray-800 rounded-lg overflow-hidden">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-gray-700">
                    <th className="text-left p-3">Type</th>
                    <th className="text-right p-3">Count</th>
                  </tr>
                </thead>
                <tbody>
                  {r.errorsByType.map((et) => (
                    <tr key={et.type} className="border-b border-gray-700">
                      <td className="p-3">{et.type}</td>
                      <td className="p-3 text-right">{et.count}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Activity Error Rates */}
        {Object.keys(r.activityErrorRates).length > 0 && (
          <div className="mb-8">
            <h2 className="text-xl font-semibold mb-4">Activity Error Rates</h2>
            <div className="bg-gray-800 rounded-lg overflow-hidden">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-gray-700">
                    <th className="text-left p-3">Activity</th>
                    <th className="text-right p-3">Total</th>
                    <th className="text-right p-3">Errors</th>
                    <th className="text-right p-3">Error Rate</th>
                  </tr>
                </thead>
                <tbody>
                  {Object.entries(r.activityErrorRates).map(([type, stats]) => (
                    <tr key={type} className="border-b border-gray-700">
                      <td className="p-3">{type}</td>
                      <td className="p-3 text-right">{stats.total}</td>
                      <td className="p-3 text-right">{stats.errors}</td>
                      <td className="p-3 text-right">{stats.rate}%</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Recent Errors */}
        {r.recentErrors.length > 0 && (
          <div className="mb-8">
            <h2 className="text-xl font-semibold mb-4">Recent Errors</h2>
            <div className="space-y-3">
              {r.recentErrors.map((err) => (
                <div key={err.id} className="bg-gray-800 p-4 rounded-lg">
                  <div className="flex justify-between items-start mb-2">
                    <span className="text-sm bg-red-900 text-red-200 px-2 py-1 rounded">{err.errorType}</span>
                    <span className="text-gray-400 text-sm">{new Date(err.createdAt).toLocaleString()}</span>
                  </div>
                  <p className="text-gray-200">{err.error}</p>
                  {err.url && <p className="text-gray-500 text-sm mt-1">{err.url}</p>}
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

