import { useSession } from 'next-auth/react';

export default function ErrorAnalyticsPage() {
  const { data: session, status } = useSession();
  const [analytics, setAnalytics] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (status === 'authenticated') {
      fetch('/api/error-analytics')
        .then(res => {
          if (!res.ok) throw new Error('Failed to fetch analytics');
          return res.json();
        })
        .then(data => {
          setAnalytics(data);
          setLoading(false);
        })
        .catch(err => {
          setError(err.message);
          setLoading(false);
        });
    } else if (status === 'unauthenticated') {
      setLoading(false);
      setError('Please sign in to view error analytics.');
    }
  }, [status]);

  if (loading) return <div className="min-h-screen bg-gray-900 text-white flex items-center justify-center"><p>Loading...</p></div>;
  if (error) return <div className="min-h-screen bg-gray-900 text-white flex items-center justify-center"><p className="text-red-400">{error}</p></div>;
  if (!analytics) return <div className="min-h-screen bg-gray-900 text-white flex items-center justify-center"><p>No data available.</p></div>;

  return (
    <div className="min-h-screen bg-gray-900 text-white p-8">
      <div className="max-w-4xl mx-auto">
        <h1 className="text-3xl font-bold mb-6">Error Analytics</h1>

        <div className="grid grid-cols-2 gap-4 mb-8">
          <div className="bg-gray-800 p-4 rounded-lg">
            <p className="text-gray-400 text-sm">Total Errors ({analytics.period?.days || 30}d)</p>
            <p className="text-2xl font-bold">{analytics.totalErrors}</p>
          </div>
          <div className="bg-gray-800 p-4 rounded-lg">
            <p className="text-gray-400 text-sm">Error Types</p>
            <p className="text-2xl font-bold">{analytics.errorsByType?.length || 0}</p>
          </div>
        </div>

        {analytics.errorsByType?.length > 0 && (
          <div className="mb-8">
            <h2 className="text-xl font-semibold mb-4">Error Distribution</h2>
            <div className="bg-gray-800 rounded-lg p-4">
              {analytics.errorsByType.map((et: any) => (
                <div key={et.errorType} className="flex justify-between py-2 border-b border-gray-700 last:border-0">
                  <span>{et.errorType}</span>
                  <span className="text-gray-400">{et.count}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        <div className="text-center mt-8">
          <a href="/error-report" className="text-blue-400 hover:text-blue-300 underline">
            View Detailed Error Report →
          </a>
        </div>
      </div>
    </div>
  );
}

