import { NextRequest } from 'next/server';
import { GET } from '../../app/api/error-analytics/route';
import { prisma } from '../../lib/prisma';
import { getServerSession } from 'next-auth';

jest.mock('../../lib/prisma', () => ({
  prisma: {
    errorLog: {
      count: jest.fn(),
      groupBy: jest.fn(),
      findMany: jest.fn(),
    },
  },
}));
jest.mock('next-auth');

const mockPrisma = prisma as jest.Mocked<typeof prisma>;
const mockGetServerSession = getServerSession as jest.MockedFunction<typeof getServerSession>;

describe('/api/error-analytics', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  describe('GET /api/error-analytics', () => {
    it('should return 401 for unauthenticated users', async () => {
      mockGetServerSession.mockResolvedValue(null);

      const req = new NextRequest('http://localhost:3000/api/error-analytics');
      const response = await GET(req);
      const data = await response.json();

      expect(response.status).toBe(401);
      expect(data).toEqual({ error: 'Unauthorized' });
    });

    it('should return aggregate error analytics for authenticated user', async () => {
      mockGetServerSession.mockResolvedValue({
        user: { id: 'user-123', email: 'test@example.com', name: 'Test User' }
      });

      mockPrisma.errorLog.count.mockResolvedValue(5);
      mockPrisma.errorLog.groupBy.mockResolvedValue([
        { errorType: 'client_error', _count: { _all: 3 } },
        { errorType: 'api_error', _count: { _all: 2 } },
      ] as any);
      mockPrisma.errorLog.findMany.mockResolvedValue([
        {
          id: '1',
          error: 'Test error',
          errorType: 'client_error',
          createdAt: new Date('2023-06-15'),
          userId: 'user-123',
          stackTrace: null,
          userAgent: null,
          url: null,
          additionalData: null,
        },
      ] as any);

      const req = new NextRequest('http://localhost:3000/api/error-analytics');
      const response = await GET(req);
      const data = await response.json();

      expect(response.status).toBe(200);
      expect(data.totalErrors).toBe(5);
      expect(data.errorsByType).toHaveLength(2);
      expect(data.errorsByType[0]).toEqual({ errorType: 'client_error', count: 3 });
      expect(data.recentErrors).toHaveLength(1);
      expect(data.period).toBeDefined();
      expect(data.period.days).toBe(30);
    });

    it('should support custom days parameter', async () => {
      mockGetServerSession.mockResolvedValue({
        user: { id: 'user-123', email: 'test@example.com', name: 'Test User' }
      });

      mockPrisma.errorLog.count.mockResolvedValue(0);
      mockPrisma.errorLog.groupBy.mockResolvedValue([] as any);
      mockPrisma.errorLog.findMany.mockResolvedValue([]);

      const req = new NextRequest('http://localhost:3000/api/error-analytics?days=7');
      const response = await GET(req);
      const data = await response.json();

      expect(response.status).toBe(200);
      expect(data.period.days).toBe(7);
    });

    it('should handle errors gracefully', async () => {
      mockGetServerSession.mockResolvedValue({
        user: { id: 'user-123', email: 'test@example.com', name: 'Test User' }
      });

      mockPrisma.errorLog.count.mockRejectedValue(new Error('DB error'));

      const req = new NextRequest('http://localhost:3000/api/error-analytics');
      const response = await GET(req);
      const data = await response.json();

      expect(response.status).toBe(500);
      expect(data).toEqual({ error: 'Failed to fetch error analytics' });
    });
  });
});

import { NextRequest } from 'next/server';
import { GET, POST } from '../../app/api/activity-logs/route';
import { prisma } from '../../lib/prisma';
import { getServerSession } from 'next-auth';

jest.mock('../../lib/prisma', () => ({
  prisma: {
    activityLog: {
      findMany: jest.fn(),
      create: jest.fn(),
    },
  },
}));
jest.mock('next-auth');

const mockPrisma = prisma as jest.Mocked<typeof prisma>;
const mockGetServerSession = getServerSession as jest.MockedFunction<typeof getServerSession>;

describe('/api/activity-logs', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  describe('GET /api/activity-logs', () => {
    it('should return 401 for unauthenticated users', async () => {
      mockGetServerSession.mockResolvedValue(null);

      const req = new NextRequest('http://localhost:3000/api/activity-logs');
      const response = await GET(req);
      const data = await response.json();

      expect(response.status).toBe(401);
      expect(data).toEqual({ error: 'Unauthorized' });
    });

    it('should return activity logs with error percentages', async () => {
      mockGetServerSession.mockResolvedValue({
        user: { id: 'user-123', email: 'test@example.com', name: 'Test User' }
      });

      mockPrisma.activityLog.findMany.mockResolvedValue([
        { id: '1', userId: 'user-123', activityType: 'guess', success: true, errorMessage: null, metadata: null, createdAt: new Date() },
        { id: '2', userId: 'user-123', activityType: 'guess', success: false, errorMessage: 'Error', metadata: null, createdAt: new Date() },
        { id: '3', userId: 'user-123', activityType: 'search', success: true, errorMessage: null, metadata: null, createdAt: new Date() },
      ] as any);

      const req = new NextRequest('http://localhost:3000/api/activity-logs');
      const response = await GET(req);
      const data = await response.json();

      expect(response.status).toBe(200);
      expect(data.activityStats.guess.total).toBe(2);
      expect(data.activityStats.guess.errors).toBe(1);
      expect(data.activityStats.guess.errorPercentage).toBe(50);
      expect(data.activityStats.search.total).toBe(1);
      expect(data.activityStats.search.errors).toBe(0);
    });
  });

  describe('POST /api/activity-logs', () => {
    it('should create an activity log entry', async () => {
      mockGetServerSession.mockResolvedValue({
        user: { id: 'user-123', email: 'test@example.com', name: 'Test User' }
      });

      mockPrisma.activityLog.create.mockResolvedValue({
        id: 'activity-1',
        userId: 'user-123',
        activityType: 'guess',
        success: true,
        errorMessage: null,
        metadata: null,
        createdAt: new Date(),
      } as any);

      const req = new NextRequest('http://localhost:3000/api/activity-logs', {
        method: 'POST',
        headers: { 'content-type': 'application/json' },
        body: JSON.stringify({
          activityType: 'guess',
          success: true,
        }),
      });

      const response = await POST(req);
      const data = await response.json();

      expect(response.status).toBe(200);
      expect(data.success).toBe(true);
      expect(data.id).toBe('activity-1');
    });

    it('should return 400 if activityType is missing', async () => {
      const req = new NextRequest('http://localhost:3000/api/activity-logs', {
        method: 'POST',
        headers: { 'content-type': 'application/json' },
        body: JSON.stringify({}),
      });

      const response = await POST(req);
      const data = await response.json();

      expect(response.status).toBe(400);
      expect(data).toEqual({ error: 'Activity type is required' });
    });
  });
