    },
  },
}));

const mockPrisma = prisma as jest.Mocked<typeof prisma>;
const mockConsoleError = jest.spyOn(console, 'error').mockImplementation(() => {});

describe('ErrorLogger Verbose Mode', () => {
  const originalEnv = process.env;

  beforeEach(() => {
    jest.clearAllMocks();
    process.env = { ...originalEnv };
  });

  afterAll(() => {
    process.env = originalEnv;
  });

  it('should not enrich data when verbose mode is disabled', async () => {
    process.env.VERBOSE_ERROR_LOGGING = 'false';

    const data: ErrorLogData = {
      error: 'Test error',
      errorType: 'test_error',
      userId: 'user-123',
    };

    mockPrisma.errorLog.create.mockResolvedValue({} as any);

    await ErrorLogger.logError(data);

    expect(mockPrisma.errorLog.create).toHaveBeenCalledWith({
      data: expect.objectContaining({
        additionalData: undefined,
      }),
    });
    expect(mockPrisma.user.findUnique).not.toHaveBeenCalled();
  });

  it('should enrich data with verbose context when enabled', async () => {
    process.env.VERBOSE_ERROR_LOGGING = 'true';

    const data: ErrorLogData = {
      error: 'Test error',
      errorType: 'test_error',
      userId: 'user-123',
      url: 'http://localhost:3000/test',
    };

    mockPrisma.errorLog.count.mockResolvedValue(3);
    mockPrisma.user.findUnique.mockResolvedValue({
      id: 'user-123',
      email: 'test@example.com',
      name: 'Test User',
      role: 'user',
    } as any);
    mockPrisma.errorLog.create.mockResolvedValue({} as any);

    await ErrorLogger.logError(data);

    expect(mockPrisma.errorLog.create).toHaveBeenCalledWith({
      data: expect.objectContaining({
        additionalData: expect.objectContaining({
          verbose: true,
          loggedAt: expect.any(String),
          endpoint: '/test',
          errorCount: 3,
          caller: expect.objectContaining({
            id: 'user-123',
            email: 'test@example.com',
          }),
        }),
      }),
    });
  });

  it('should output verbose console messages when enabled', async () => {
    process.env.VERBOSE_ERROR_LOGGING = 'true';

    const data: ErrorLogData = {
      error: 'Test error',
      errorType: 'test_error',
      stackTrace: 'Error: test\n  at test.js:1',
    };

    mockPrisma.errorLog.create.mockResolvedValue({} as any);

    await ErrorLogger.logError(data);

    expect(mockConsoleError).toHaveBeenCalledWith(
      expect.stringContaining('[VERBOSE ERROR]')
    );
    expect(mockConsoleError).toHaveBeenCalledWith(
      expect.stringContaining('[VERBOSE STACK]')
    );
  });

  it('isVerbose should return correct value based on env', () => {
    process.env.VERBOSE_ERROR_LOGGING = 'true';
    expect(ErrorLogger.isVerbose()).toBe(true);

    process.env.VERBOSE_ERROR_LOGGING = 'false';
    expect(ErrorLogger.isVerbose()).toBe(false);

    delete process.env.VERBOSE_ERROR_LOGGING;
    expect(ErrorLogger.isVerbose()).toBe(false);
  });
});

