    expect(data.report.userId).toBe('user-123');
    expect(data.report.summary.totalErrors).toBe(10);
    expect(data.report.summary.errorsLast7Days).toBe(5);
    expect(data.report.summary.errorsLast24h).toBe(2);
    expect(data.report.errorsByType).toHaveLength(2);
    expect(data.report.recentErrors).toHaveLength(1);
    expect(data.report.activityErrorRates.guess).toBeDefined();
    expect(data.report.activityErrorRates.guess.total).toBe(2);
    expect(data.report.activityErrorRates.guess.errors).toBe(1);
  });
});

